/**
 * @summary Upload a handwritten paper for OCR processing
 */
export const getUploadPaperUrl = () => {
  return `/api/uploads`;
};

export const uploadPaper = async (
  uploadPaperBody: UploadPaperBody,
  options?: RequestInit,
): Promise<PaperUpload> => {
  const formData = new FormData();
  formData.append(`file`, uploadPaperBody.file);
  if (uploadPaperBody.studentId !== undefined) {
    formData.append(`studentId`, uploadPaperBody.studentId.toString());
  }
  formData.append(`classId`, uploadPaperBody.classId.toString());
  if (uploadPaperBody.description !== undefined) {
    formData.append(`description`, uploadPaperBody.description);
  }

  return customFetch<PaperUpload>(getUploadPaperUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

